export function getFolders() {
  if (typeof window === "undefined") return [];

  const data = localStorage.getItem("folders");

  if (!data) {
    const defaultFolders = [
      {
        id: 1,
        name: "Aqidah",
        materi: [],
      },
      {
        id: 2,
        name: "Akhlak",
        materi: [],
      },
    ];

    localStorage.setItem("folders", JSON.stringify(defaultFolders));
    return defaultFolders;
  }

  return JSON.parse(data);
}

export function saveFolders(folders) {
  localStorage.setItem("folders", JSON.stringify(folders));
}

export function addMateriToFolder(folderId, materi) {
  const folders = getFolders();

  const updated = folders.map((folder) => {
    if (folder.id === folderId) {
      return {
        ...folder,
        materi: [...folder.materi, materi],
      };
    }
    return folder;
  });

  saveFolders(updated);
}

export function updateMateri(folderId, updatedMateri) {
  const folders = getFolders();

  const updated = folders.map((folder) => {
    if (folder.id === folderId) {
      return {
        ...folder,
        materi: folder.materi.map((item) =>
          item.id === updatedMateri.id ? updatedMateri : item,
        ),
      };
    }
    return folder;
  });

  saveFolders(updated);
}

<button
  onClick={() => {
    deleteMateri(currentFolder.id, selected.id);

    const updated = getFolders();
    setFolders(updated);

    const updatedCurrent = updated.find(f => f.id === currentFolder.id);
    setCurrentFolder(updatedCurrent);

    setSelected(null);
  }}
  className="flex-1 bg-red-500 text-white py-2 rounded-lg"
>
  Delete
</button>